@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRouting]
@inject Microsoft.AspNetCore.Http.IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✔ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This site uses cookies to improve your experience. We use cookies to remember
    your preferences and to understand how you interact with our application.
</p>

<h2>Your Data</h2>
<p>
    We are committed to protecting your personal data. We do not sell your
    information to third parties.
</p>

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var context = HttpContextAccessor.HttpContext;
        if (context is not null)
        {
            _hasConsent = context.Request.Cookies.ContainsKey("consent");
        }
    }
}

